    client = Client(wsdl=wsdl_url, transport=transport, settings=settings)
    if service_address:
        client.service._binding_options["address"] = service_address

    # Build a SOAP body by directly inserting user-provided values into XML
    body = etree.Element(etree.QName("urn:InsuranceService", operation), nsmap={"urn": "urn:InsuranceService"})
    etree.SubElement(body, "PolicyNumber").text = policy_number
    etree.SubElement(body, "CustomerName").text = customer_name

    headers = {}
